import sqlite3

def build_query(clauses):
    query = "SELECT * FROM your_table_name WHERE "
    conditions = []
    
    for clause in clauses:
        field = clause['field']
        op = clause['op']
        value = clause['value']
        
        # Ensure safe handling of input to prevent SQL injection
        if isinstance(value, str):
            value = f"'{sqlite3.escape_string(value)}'"
        elif isinstance(value, (int, float)):
            value = str(value)
        
        conditions.append(f"{field} {op} {value}")
    
    query += " AND ".join(conditions)
    return query

def search(clauses):
    conn = sqlite3.connect('your_database.db')
    cursor = conn.cursor()
    
    sql_query = build_query(clauses)
    print(sql_query)  # Debugging to see the constructed SQL
    
    try:
        cursor.execute(sql_query)
        results = cursor.fetchall()
        return results
    except sqlite3.Error as e:
        print(f"An error occurred: {e}")
        return []
    finally:
        conn.close()

